import{_ as r,o as l,c as i,ag as t}from"./chunks/framework.CrllrrHC.js";const u=JSON.parse('{"title":"Mac 低内存终端工具","description":"","frontmatter":{"new_folder":"utils","title":"Mac 低内存终端工具","slug":"termianl","date":"2026年05月08日"},"headers":[],"relativePath":"column/utils/terminal.md","filePath":"column/utils/terminal.md","lastUpdated":1778202870000}'),e={name:"column/utils/terminal.md"};function o(n,a,s,h,d,p){return l(),i("div",null,[...a[0]||(a[0]=[t('<p>终端工具取舍｜WindTerm + Tabby 最终组合方案</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>作为日常需要频繁连接服务器、查看日志、敲命令的后端开发，终端是我每天打开时间最长的软件。</p><p>我的硬性要求非常直白：<strong>占用内存极低、性能极致、不卡顿、无多余花哨功能</strong>。</p><p>公司电脑是 Mac，内存并不算多。我试过市面上绝大多数主流终端：Termius、iShellPro、原生终端、Warp、FinalShell……</p><p>兜兜转转一圈，最终敲定一套<strong>双终端组合方案</strong>：</p><ul><li><strong>日常命令/日志/跳板机连接：Tabby</strong></li><li><strong>文件传输、批量上传下载：WindTerm</strong></li></ul><p>这篇记录纯粹主观实测，给同样追求<strong>轻量化、低占用</strong>的程序员做参考。</p><h2 id="一、我淘汰掉的终端-踩坑总结" tabindex="-1">一、我淘汰掉的终端（踩坑总结） <a class="header-anchor" href="#一、我淘汰掉的终端-踩坑总结" aria-label="Permalink to &quot;一、我淘汰掉的终端（踩坑总结）&quot;">​</a></h2><h3 id="_1-termius-颜值天花板-内存黑洞" tabindex="-1">1. Termius｜颜值天花板，内存黑洞 <a class="header-anchor" href="#_1-termius-颜值天花板-内存黑洞" aria-label="Permalink to &quot;1. Termius｜颜值天花板，内存黑洞&quot;">​</a></h3><p>说实话 Termius 几乎样样完美：UI 好看、同步配置、标签页舒服、交互人性化。</p><p>但致命硬伤：<strong>内存占用极高，后台常驻吃资源</strong>。</p><p>Mac 开发最怕这种隐性耗内存的软件，开几个连接后台内存直接暴涨，长时间挂机非常难受。果断放弃。</p><h3 id="_2-ishellpro-轻巧好用-但功能性单一" tabindex="-1">2. iShellPro｜轻巧好用，但功能性单一 <a class="header-anchor" href="#_2-ishellpro-轻巧好用-但功能性单一" aria-label="Permalink to &quot;2. iShellPro｜轻巧好用，但功能性单一&quot;">​</a></h3><p>iShellPro 确实轻量、流畅、颜值高，日常简单连接完全够用。</p><p>短板也很明显：<strong>跳板机配置麻烦、高级管理能力偏弱</strong>，不适合我复杂多服务器、多环境跳转的工作流。</p><h3 id="_3-其他终端-warp-原生终端" tabindex="-1">3. 其他终端（Warp/原生终端） <a class="header-anchor" href="#_3-其他终端-warp-原生终端" aria-label="Permalink to &quot;3. 其他终端（Warp/原生终端）&quot;">​</a></h3><p>Warp 特效过多、吃显卡+内存；原生终端自定义太差，美观度和操作性都落后。</p><h2 id="二、最终常驻组合-tabby-windterm" tabindex="-1">二、最终常驻组合：Tabby + WindTerm <a class="header-anchor" href="#二、最终常驻组合-tabby-windterm" aria-label="Permalink to &quot;二、最终常驻组合：Tabby + WindTerm&quot;">​</a></h2><h3 id="_1-tabby-我的主力日常终端" tabindex="-1">1. Tabby｜我的主力日常终端 <a class="header-anchor" href="#_1-tabby-我的主力日常终端" aria-label="Permalink to &quot;1. Tabby｜我的主力日常终端&quot;">​</a></h3><p><strong>定位：主力敲命令、看日志、跳板机、长期挂连接</strong></p><h4 id="✅-优点" tabindex="-1">✅ 优点 <a class="header-anchor" href="#✅-优点" aria-label="Permalink to &quot;✅ 优点&quot;">​</a></h4><ul><li><strong>内存控制极其优秀</strong>：相较于 Termius，Tabby 后台占用几乎可以忽略</li><li><strong>原生支持跳板机配置</strong>：这是我保留它的最大理由，一键跳转、不用手动嵌套 ssh</li><li>标签页顺滑、分屏舒服，长时间挂日志不卡顿</li><li>跨平台，Windows/Mac 通用，配置可导出备份</li><li>开源免费，无广告、无强制会员</li></ul><h4 id="❌-缺点" tabindex="-1">❌ 缺点 <a class="header-anchor" href="#❌-缺点" aria-label="Permalink to &quot;❌ 缺点&quot;">​</a></h4><ul><li>自带文件传输一般，不如专业工具顺滑</li><li>动画特效偏多，建议手动关闭动画，进一步降低占用</li></ul><p><strong>个人使用建议：</strong></p><p>关掉所有动画、弱化美化，只保留功能性，Tabby 就是目前综合体验最好的轻量终端。</p><h3 id="_2-windterm-纯专注文件传输-批量管理" tabindex="-1">2. WindTerm｜纯专注文件传输+批量管理 <a class="header-anchor" href="#_2-windterm-纯专注文件传输-批量管理" aria-label="Permalink to &quot;2. WindTerm｜纯专注文件传输+批量管理&quot;">​</a></h3><p><strong>定位：专门用来服务器文件上传、下载、批量拖拽</strong></p><h4 id="✅-优点-1" tabindex="-1">✅ 优点 <a class="header-anchor" href="#✅-优点-1" aria-label="Permalink to &quot;✅ 优点&quot;">​</a></h4><ul><li><strong>极致轻量化</strong>：启动速度极快，内存占用极低</li><li>文件可视化，左侧本地、右侧服务器，拖拽上传下载无脑操作</li><li>传输速度稳定，比 Tabby、Termius 自带 sftp 更快</li><li>无后台冗余进程，不用直接关掉，零负担</li></ul><h4 id="❌-缺点-1" tabindex="-1">❌ 缺点 <a class="header-anchor" href="#❌-缺点-1" aria-label="Permalink to &quot;❌ 缺点&quot;">​</a></h4><ul><li>UI 偏简陋，颜值一般</li><li>跳板机体验不如 Tabby 人性化</li></ul><p>所以我不会拿它当主力敲命令，只做<strong>文件专用工具</strong>。</p><h2 id="三、我的个人工作流-适合后端开发照搬" tabindex="-1">三、我的个人工作流（适合后端开发照搬） <a class="header-anchor" href="#三、我的个人工作流-适合后端开发照搬" aria-label="Permalink to &quot;三、我的个人工作流（适合后端开发照搬）&quot;">​</a></h2><ol><li><strong>Tabby（常驻）</strong><ol><li>跳板机配置、日常服务器连接、查看服务日志、Git、Linux 命令操作</li><li>长期挂后台，内存稳定不暴涨</li></ol></li><li><strong>WindTerm（按需打开）</strong><ol><li>本地 &lt;-&gt; 服务器文件互传、打包、批量替换资源</li><li>用完即关，不留常驻内存</li></ol></li></ol><h2 id="四、总结-为什么放弃全能-选择双终端" tabindex="-1">四、总结：为什么放弃全能，选择双终端？ <a class="header-anchor" href="#四、总结-为什么放弃全能-选择双终端" aria-label="Permalink to &quot;四、总结：为什么放弃全能，选择双终端？&quot;">​</a></h2><p>以前我总想找一个“全能终端”，一个软件搞定全部。</p><p>但实际上：<strong>全能=臃肿、冗余、高内存占用。</strong></p><p>对于 Mac 内存一般、追求极致流畅的开发者：</p><ul><li>想要<strong>跳板机、常驻、低内存</strong> →<strong>Tabby</strong></li><li>想要<strong>传文件、轻量、快速</strong> → <strong>WindTerm</strong></li></ul><p>另外补充一句，本篇推荐的两款终端，<strong>日常开发刚需功能全部免费</strong>。Tabby、WindTerm 均无功能阉割、无付费锁关键能力，跳板机、连接管理、文件传输、多标签页等核心功能，普通用户完全免费就能无脑使用。哪怕不差内存、不差软件订阅费用，我也没必要去盲目上付费会员、追顶配商业终端。</p><p>纯属个人主观喜好：我向来不喜欢为冗余功能买单，也不爱过度堆砌花哨特效。工具只要贴合工作流、占用干净、逻辑简单，就足够优秀。没必要跟风追求高价全能软件，适合自己使用习惯，才是最好的选择。</p><h2 id="附加-我的终端优化小设置" tabindex="-1">附加：我的终端优化小设置 <a class="header-anchor" href="#附加-我的终端优化小设置" aria-label="Permalink to &quot;附加：我的终端优化小设置&quot;">​</a></h2><p>给同款需求的人抄作业：</p><ol><li>Tabby：关闭动画、关闭模糊、最小化美化，只保留功能；</li><li>Tabby 提前配置跳板机，避免重复输入命令；</li><li>WindTerm 不常驻， Dock 随时点开，用完即杀；</li><li>坚决不安装 Termius 这类高内存终端。</li></ol><p><strong>本文原创：个人使用记录，无恰饭、无推广，纯自用踩坑总结。</strong></p>',47)])])}const m=r(e,[["render",o]]);export{u as __pageData,m as default};
